#!/bin/bash
# ============================================================
#   CHAIYA VPN PANEL - All-in-One Install Script
#   Ubuntu 24.04 / 25.04+
#   รันคำสั่งเดียว: bash chaiya-setup.sh
# ============================================================

RED='\033[0;31m'; GREEN='\033[0;32m'; YELLOW='\033[1;33m'
CYAN='\033[0;36m'; BOLD='\033[1m'; NC='\033[0m'

ok()   { echo -e "${GREEN}[OK]${NC} $1"; }
info() { echo -e "${CYAN}[INFO]${NC} $1"; }
warn() { echo -e "${YELLOW}[WARN]${NC} $1"; }
err()  { echo -e "${RED}[ERR]${NC} $1"; exit 1; }

echo -e "${CYAN}${BOLD}"
cat << 'BANNER'
  ██████╗██╗  ██╗ █████╗ ██╗██╗   ██╗ █████╗
 ██╔════╝██║  ██║██╔══██╗██║╚██╗ ██╔╝██╔══██╗
 ██║     ███████║███████║██║ ╚████╔╝ ███████║
 ██║     ██╔══██║██╔══██║██║  ╚██╔╝  ██╔══██║
 ╚██████╗██║  ██║██║  ██║██║   ██║   ██║  ██║
  ╚═════╝╚═╝  ╚═╝╚═╝  ╚═╝╚═╝   ╚═╝   ╚═╝  ╚═╝
      VPN PANEL - ALL-IN-ONE INSTALLER v2
BANNER
echo -e "${NC}"

# ── ROOT CHECK ──────────────────────────────────────────────
[[ $EUID -ne 0 ]] && err "รันด้วย root หรือ sudo เท่านั้น"

# ── GET SERVER IP ────────────────────────────────────────────
info "กำลังดึง IP ของเครื่อง..."
SERVER_IP=$(curl -s4 https://api.ipify.org 2>/dev/null || \
            curl -s4 https://ifconfig.me 2>/dev/null || \
            hostname -I | awk '{print $1}')
[[ -z "$SERVER_IP" ]] && err "ไม่สามารถดึง IP ได้"
ok "IP: ${CYAN}$SERVER_IP${NC}"

# ── PASSWORD ─────────────────────────────────────────────────
echo ""
echo -e "${YELLOW}กำหนด Password สำหรับ Panel Login${NC}"
while true; do
  read -rsp "  Panel Password: " PANEL_PASS; echo
  read -rsp "  Confirm Password: " PANEL_PASS2; echo
  [[ "$PANEL_PASS" == "$PANEL_PASS2" ]] && break
  warn "Password ไม่ตรงกัน ลองอีกครั้ง"
done
[[ ${#PANEL_PASS} -lt 6 ]] && err "Password ต้องมีอย่างน้อย 6 ตัวอักษร"

# ── PORTS ────────────────────────────────────────────────────
SSH_API_PORT=2095
XUI_PORT=2053
PANEL_PORT=8080
DROPBEAR_PORT1=143
DROPBEAR_PORT2=109
BADVPN_PORT=7300
OPENVPN_PORT=1194

echo ""
info "การตั้งค่า:"
echo -e "  IP Server     : ${CYAN}$SERVER_IP${NC}"
echo -e "  Panel URL     : ${CYAN}http://$SERVER_IP:$PANEL_PORT${NC}"
echo -e "  SSH API Port  : ${CYAN}$SSH_API_PORT${NC}"
echo -e "  x-ui Port     : ${CYAN}$XUI_PORT${NC}"
echo -e "  Dropbear      : ${CYAN}$DROPBEAR_PORT1, $DROPBEAR_PORT2${NC}"
echo ""
read -rp "เริ่มติดตั้ง? [y/N]: " CONFIRM
[[ "$CONFIRM" != "y" && "$CONFIRM" != "Y" ]] && exit 0

# ── UPDATE ───────────────────────────────────────────────────
echo ""
info "อัปเดต package..."
apt-get update -qq && apt-get upgrade -y -qq
apt-get install -y -qq \
  curl wget git python3 python3-pip \
  nginx dropbear openssh-server ufw \
  build-essential cmake net-tools \
  jq bc cron unzip || err "ติดตั้ง packages ล้มเหลว"
ok "ติดตั้ง packages สำเร็จ"

# ── OPENSSH ──────────────────────────────────────────────────
info "ตั้งค่า OpenSSH..."
sed -i 's/#PermitRootLogin.*/PermitRootLogin yes/' /etc/ssh/sshd_config
sed -i 's/#PasswordAuthentication.*/PasswordAuthentication yes/' /etc/ssh/sshd_config
systemctl restart ssh
ok "OpenSSH พร้อม"

# ── DROPBEAR ─────────────────────────────────────────────────
info "ตั้งค่า Dropbear..."
cat > /etc/default/dropbear << EOF
NO_START=0
DROPBEAR_PORT=$DROPBEAR_PORT1
DROPBEAR_EXTRA_ARGS="-p $DROPBEAR_PORT2"
DROPBEAR_BANNER="/etc/issue.net"
EOF
cat > /etc/issue.net << 'EOF'
━━━━━━━━━━━━━━━━━━━━━━━━━━━
   CHAIYA VPN SERVER
   Authorized Access Only
━━━━━━━━━━━━━━━━━━━━━━━━━━━
EOF
systemctl enable dropbear
systemctl restart dropbear
ok "Dropbear พร้อม (port $DROPBEAR_PORT1, $DROPBEAR_PORT2)"

# ── BADVPN ───────────────────────────────────────────────────
info "ติดตั้ง BadVPN..."
if ! command -v badvpn-udpgw &>/dev/null; then
  cd /tmp
  wget -q https://github.com/ambrop72/badvpn/archive/refs/heads/master.zip -O badvpn.zip
  unzip -q badvpn.zip
  cd badvpn-master
  cmake . -DBUILD_NOTHING_BY_DEFAULT=1 -DBUILD_UDPGW=1 -DCMAKE_INSTALL_PREFIX=/usr/local &>/dev/null
  make -j$(nproc) &>/dev/null
  make install &>/dev/null
  cd /
  rm -rf /tmp/badvpn*
fi
cat > /etc/systemd/system/badvpn.service << EOF
[Unit]
Description=BadVPN UDP Gateway
After=network.target
[Service]
ExecStart=/usr/local/bin/badvpn-udpgw --listen-addr 127.0.0.1:$BADVPN_PORT --max-clients 1000
Restart=always
RestartSec=3
[Install]
WantedBy=multi-user.target
EOF
systemctl daemon-reload
systemctl enable badvpn
systemctl start badvpn
ok "BadVPN พร้อม (port $BADVPN_PORT)"

# ── SSH API ──────────────────────────────────────────────────
info "ติดตั้ง SSH API..."
mkdir -p /opt/chaiya-ssh-api /etc/chaiya/exp

cat > /opt/chaiya-ssh-api/app.py << 'PYEOF'
#!/usr/bin/env python3
from http.server import HTTPServer, BaseHTTPRequestHandler
import json, subprocess, os, datetime, socket

def respond(handler, code, data):
    body = json.dumps(data).encode()
    handler.send_response(code)
    handler.send_header('Content-Type', 'application/json')
    handler.send_header('Content-Length', len(body))
    handler.send_header('Access-Control-Allow-Origin', '*')
    handler.send_header('Access-Control-Allow-Methods', 'GET,POST,OPTIONS')
    handler.send_header('Access-Control-Allow-Headers', 'Content-Type,Authorization')
    handler.end_headers()
    handler.wfile.write(body)

def run_cmd(cmd):
    r = subprocess.run(cmd, shell=True, capture_output=True, text=True)
    return r.returncode == 0, r.stdout.strip(), r.stderr.strip()

class Handler(BaseHTTPRequestHandler):
    def log_message(self, *args): pass

    def do_OPTIONS(self):
        self.send_response(200)
        self.send_header('Access-Control-Allow-Origin', '*')
        self.send_header('Access-Control-Allow-Methods', 'GET,POST,OPTIONS')
        self.send_header('Access-Control-Allow-Headers', 'Content-Type,Authorization')
        self.end_headers()

    def body(self):
        l = int(self.headers.get('Content-Length', 0))
        return json.loads(self.rfile.read(l)) if l else {}

    def do_GET(self):
        if self.path == '/api/users':
            users = []
            try:
                with open('/etc/passwd') as f:
                    for line in f:
                        p = line.strip().split(':')
                        if len(p) < 7: continue
                        uid = int(p[2])
                        if uid < 1000 or uid > 60000: continue
                        if p[6] not in ['/bin/bash','/bin/sh']: continue
                        u = {'user': p[0], 'active': True, 'ip_limit': 2,
                             'exp': None, 'data_gb': 0, 'used_gb': 0}
                        exp_f = f'/etc/chaiya/exp/{p[0]}'
                        if os.path.exists(exp_f):
                            u['exp'] = open(exp_f).read().strip()
                        users.append(u)
            except: pass
            respond(self, 200, {'ok': True, 'users': users})

        elif self.path == '/api/status':
            svcs = {}
            for s in ['ssh','dropbear','nginx','badvpn']:
                ok2, _, _ = run_cmd(f'systemctl is-active {s}')
                svcs[s] = ok2
            ok3, out, _ = run_cmd("ss -tn | grep ESTAB | wc -l")
            ok4, out2, _ = run_cmd("who | wc -l")
            ok5, out3, _ = run_cmd("cat /etc/passwd | awk -F: '$3>=1000 && $3<60000' | wc -l")
            svcs['sshws'] = svcs.get('ssh', False)
            svcs['tunnel'] = True
            respond(self, 200, {'ok': True, 'services': svcs,
                'connections': int(out) if ok3 else 0,
                'online': int(out2) if ok4 else 0,
                'online_count': int(out2) if ok4 else 0,
                'total_users': int(out3) if ok5 else 0,
                'conn_80': 0, 'conn_143': 0, 'conn_109': 0, 'conn_22': 0})

        elif self.path == '/api/info':
            try: ip = socket.gethostbyname(socket.gethostname())
            except: ip = '127.0.0.1'
            respond(self, 200, {'ok': True, 'host': ip})
        else:
            respond(self, 404, {'error': 'Not found'})

    def do_POST(self):
        data = self.body()
        if self.path == '/api/create':
            user = data.get('user','').strip()
            pw   = data.get('pass','').strip()
            days = int(data.get('exp_days', data.get('days', 30)))
            if not user or not pw:
                return respond(self, 400, {'error': 'user/pass required'})
            ok1, _, e1 = run_cmd(f"useradd -m -s /bin/bash {user}")
            if not ok1 and 'already exists' not in e1:
                return respond(self, 500, {'error': e1})
            run_cmd(f"echo '{user}:{pw}' | chpasswd")
            exp = (datetime.date.today() + datetime.timedelta(days=days)).isoformat()
            os.makedirs('/etc/chaiya/exp', exist_ok=True)
            with open(f'/etc/chaiya/exp/{user}', 'w') as f: f.write(exp)
            run_cmd(f"chage -E {exp} {user}")
            respond(self, 200, {'ok': True, 'user': user, 'exp': exp})

        elif self.path == '/api/delete':
            user = data.get('user','').strip()
            if not user: return respond(self, 400, {'error': 'user required'})
            run_cmd(f"userdel -r {user} 2>/dev/null")
            run_cmd(f"rm -f /etc/chaiya/exp/{user}")
            respond(self, 200, {'ok': True})
        else:
            respond(self, 404, {'error': 'Not found'})

if __name__ == '__main__':
    port = int(os.environ.get('SSH_API_PORT', 2095))
    print(f'Chaiya SSH API :{port}')
    HTTPServer(('0.0.0.0', port), Handler).serve_forever()
PYEOF

cat > /etc/systemd/system/chaiya-ssh-api.service << EOF
[Unit]
Description=Chaiya SSH API
After=network.target
[Service]
ExecStart=/usr/bin/python3 /opt/chaiya-ssh-api/app.py
Environment=SSH_API_PORT=$SSH_API_PORT
Restart=always
RestartSec=3
[Install]
WantedBy=multi-user.target
EOF
systemctl daemon-reload
systemctl enable chaiya-ssh-api
systemctl start chaiya-ssh-api
ok "SSH API พร้อม (port $SSH_API_PORT)"

# ── 3X-UI ────────────────────────────────────────────────────
info "ติดตั้ง 3x-ui..."
echo "y" | bash <(curl -Ls https://raw.githubusercontent.com/mhsanaei/3x-ui/master/install.sh) &>/dev/null
ok "3x-ui พร้อม (port $XUI_PORT)"

# ── PANEL DIR + config.js ─────────────────────────────────────
info "สร้าง Panel files..."
mkdir -p /opt/chaiya-panel

# สร้าง config.js พร้อม IP และ password hash อัตโนมัติ
PASS_HASH=$(echo -n "$PANEL_PASS" | sha256sum | cut -d' ' -f1)

cat > /opt/chaiya-panel/config.js << EOF
// Auto-generated by chaiya-setup.sh — DO NOT EDIT MANUALLY
window.CHAIYA_CONFIG = {
  host:         "$SERVER_IP",
  ssh_api_port: $SSH_API_PORT,
  xui_port:     $XUI_PORT,
  xui_user:     "admin",
  xui_pass:     "admin",
  ssh_token:    "",
  panel_pass:   "$PASS_HASH"
};
EOF

# ── DECODE และเขียน panel HTML ───────────────────────────────
info "เขียน Panel HTML..."
PANEL_HTML_B64=""
echo "$PANEL_HTML_B64" | base64 -d > /opt/chaiya-panel/index.html
ok "Panel HTML พร้อม"

# ── NGINX ────────────────────────────────────────────────────
info "ตั้งค่า Nginx..."
rm -f /etc/nginx/sites-enabled/default

cat > /etc/nginx/sites-available/chaiya << EOF
server {
    listen $PANEL_PORT;
    server_name _;
    root /opt/chaiya-panel;
    index index.html;
    add_header Access-Control-Allow-Origin *;
    location / {
        try_files \$uri \$uri/ =404;
    }
}
EOF

ln -sf /etc/nginx/sites-available/chaiya /etc/nginx/sites-enabled/
nginx -t &>/dev/null && systemctl restart nginx
ok "Nginx พร้อม (port $PANEL_PORT)"

# ── FIREWALL ─────────────────────────────────────────────────
info "ตั้งค่า Firewall..."
ufw --force reset &>/dev/null
ufw default deny incoming &>/dev/null
ufw default allow outgoing &>/dev/null
for port in 22 80 $PANEL_PORT $DROPBEAR_PORT1 $DROPBEAR_PORT2 \
            $SSH_API_PORT $XUI_PORT $BADVPN_PORT $OPENVPN_PORT; do
  ufw allow $port &>/dev/null
done
ufw --force enable &>/dev/null
ok "Firewall พร้อม"

# ── OPENVPN ──────────────────────────────────────────────────
info "ติดตั้ง OpenVPN..."
apt-get install -y -qq openvpn easy-rsa
ok "OpenVPN พร้อม"

# ── SUMMARY ──────────────────────────────────────────────────
echo ""
echo -e "${GREEN}${BOLD}════════════════════════════════════════════${NC}"
echo -e "${GREEN}${BOLD}   CHAIYA VPN PANEL - ติดตั้งสำเร็จ! 🚀${NC}"
echo -e "${GREEN}${BOLD}════════════════════════════════════════════${NC}"
echo ""
echo -e "  🌐 Panel URL      : ${CYAN}http://$SERVER_IP:$PANEL_PORT${NC}"
echo -e "  🔑 Panel Password : ${YELLOW}$PANEL_PASS${NC}"
echo -e "  🔧 SSH API        : ${CYAN}http://$SERVER_IP:$SSH_API_PORT${NC}"
echo -e "  📊 3x-ui Panel    : ${CYAN}http://$SERVER_IP:$XUI_PORT${NC}"
echo -e "  🐻 Dropbear       : ${CYAN}port $DROPBEAR_PORT1, $DROPBEAR_PORT2${NC}"
echo -e "  🎮 BadVPN         : ${CYAN}port $BADVPN_PORT${NC}"
echo ""
echo -e "${YELLOW}  ⚠️  เปลี่ยน password 3x-ui ใน panel แล้วอัปเดต config.js ด้วย${NC}"
echo -e "${YELLOW}     แก้ไข: /opt/chaiya-panel/config.js${NC}"
echo ""
echo -e "${GREEN}${BOLD}════════════════════════════════════════════${NC}"
echo ""
echo -e "  เปิดหน้า Panel ได้เลยที่:"
echo -e "  ${CYAN}${BOLD}http://$SERVER_IP:$PANEL_PORT${NC}"
echo ""
